sql:
SELECT version
FROM jmr_versions
WHERE security_patches > 1;

SELECT COUNT(*) 
FROM jmr_versions 
WHERE security_patches > 0;

SELECT version AS jmr_version, security_patches AS total_security_patches
FROM jmr_versions
WHERE security_patches > 2;

SELECT version, eol_date
FROM jmr_versions
WHERE security_patches > 1;

SELECT version, security_patches 
FROM jmr_versions 
ORDER BY security_patches DESC;

SELECT version
FROM jmr_versions
WHERE security_patches = (SELECT MAX(security_patches) FROM jmr_versions);

SELECT release_date
FROM linux_versions
WHERE linux_id = 0;

SELECT version, release_date
FROM jmr_versions
WHERE security_patches > 2;

SELECT version, security_patches
FROM java_versions
ORDER BY security_patches DESC;

SELECT version, release_date
FROM jmr_versions
WHERE jmr_id = 0;

SELECT documentation
FROM documentations
WHERE jmr_id = 0;

SELECT version, eol_date
FROM jmr_versions
WHERE release_date = '2021-06-01';

SELECT version, release_date, documentation, eol_date, security_patches, download_url
FROM jmr_versions
WHERE security_patches = (SELECT MAX(security_patches) FROM jmr_versions);

SELECT version
FROM jmr_versions
WHERE release_date > '2021-01-01';

SELECT documentation, version, last_updated
FROM documentations
ORDER BY last_updated DESC;

external_knowledge:
- JMRI (Java Model Railroad Interface) is a Java-based software for controlling and automating model railroads;
- End-of-Life (EOL) date refers to the date after which a software version is no longer supported or maintained;
- Security patches are updates that fix security vulnerabilities in software;
- Cumulative security updates refer to the total number of security patches applied to a software version over time;
- Average security updates refer to the average number of security patches applied to a software version.
